{
  "name": "SNAP",
  "eligibility": {
    "age": 60,
    "income_limits": "For households with a member 60+ or disabled, Pennsylvania uses expanded rules (Oct 1, 2025–Sept 30, 2026). Gross income limit at 200% federal poverty level: 1 person $2608/month, 2 $3526, 3 $4442, 4 $5358, 5 $6276, 6 $7192, 7 $8108, +$916 each additional. If over gross, qualify via net income and asset tests. Alternative 2025 senior limits cited: 1 person $15,060/year ($1255/month), 2 $20,440/year ($1703/month). Net income determines benefits after deductions (e.g., 30% of net from max allotment).[1][2][3]",
    "asset_limits": "Applies if gross income >200% FPL; must meet net income + asset test. Exempt: home value, retirement savings, household goods, life insurance cash value (if not income-producing), income-producing property (varies by state). Most states waive asset test if income ≤ federal poverty line.[1][2]",
    "other_requirements": ["Household must live in PA", "U.S. citizen or qualified non-citizen (note: Nov 1, 2025 changes restrict many immigrants; green card/Cuba/Haiti may still qualify)", "SSN for all members", "Work rules exempt for 60+ (but new Sep 1, 2025 rules for some adults under 60)"]
  },
  "benefits": {
    "type": "financial",
    "value": "Monthly EBT card for food purchases. Average for older adults: $106/month. Calculated as max allotment minus 30% net income (e.g., 2-person elderly: $546 max - 30% net). Varies by net income, deductions (medical >$35 for 60+, shelter, utilities). Min/max allotments by household size.[1][4][5]",
    "varies_by": "household_size"
  },
  "application": {
    "methods": ["Online: COMPASS website (pa.gov COMPASS tool)", "Phone: County Assistance Office (e.g., senior helpline 1-877-999-5964)", "In-person: County assistance office", "Mail: Use Simple SNAP application form"],
    "processing_time": "Not specified in sources; apply to check.",
    "waitlist": null,
    "forms": ["Simple SNAP application (for households all 60+ or disabled, purchase/prepare food together)"],
    "documents": ["Dates of birth", "Social Security numbers", "Household income (SS, pensions, etc.)", "Expenses (housing, medical >$35 for 60+, utilities)", "Proof of shelter/utility costs (required as of Feb 9, 2026, if not on file; updates if move)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; apply via county assistance office",
    "regional_variations": "Administered by county offices; potential wait/processing differences not detailed",
    "offices_or_providers": ["County assistance offices statewide"]
  },
  "official_source": "https://www.pa.gov/agencies/dhs/resources/snap/snap-older-adults",
  "gotchas": ["Expanded PA rules looser than federal—check PA-specific limits", "Medical/shelter deductions key for seniors to maximize benefits", "New 2025/2026 changes: immigrant restrictions (Nov 1), work rules (Sep 1, exempt 60+), shelter/utility proof (Feb 9, 2026)", "Include all who buy/prepare food", "Assets exempt but test applies if high gross income"],
  "data_shape_notes": "benefits scale by household size; expanded gross limit (200% FPL) for 60+/disabled with net/asset fallback; high deductions for seniors (medical, shelter); county-administered with 2025-2026 federal changes"
}

{
  "name": "LIHEAP",
  "eligibility": {
    "age": null,
    "income_limits": "For the 2025-2026 heating season (effective through at least February 1, 2026), maximum annual gross income at or below 150% of Federal Poverty Guidelines: Household Size 1: $23,940; 2: $32,460; 3: $40,980; 4: $49,500; 5: $58,020; 6: $66,540; 7: $75,060; 8: $83,580; 9: $92,100; 10: $100,620. For each additional person, add $8,520. Income includes gross yearly earnings of all household members (related or unrelated, including roomers sharing expenses). Exclusions include certain educational assistance, home produce for consumption, Senior Citizen Rebate payments, and work/training incentives[1][2][4][7].",
    "asset_limits": "No resource or asset limits apply[5].",
    "other_requirements": ["Must reside in Pennsylvania", "Renters and homeowners both eligible", "No requirement to be on other public assistance", "No requirement for unpaid heating bills", "Household includes all children, adults, relatives, and unrelated roomers sharing expenses at the residence[1][2][4][5]"]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time cash grant of $200 to $1,000 paid directly to utility company or fuel provider. Exact amount determined by household size, income, fuel type, and county-specific benefit tables. Crisis grants available for households in immediate danger of being without heat. Grants are non-repayable[2][4][8].",
    "varies_by": "household_size|priority_tier|region"
  },
  "application": {
    "methods": ["Online: COMPASS at https://www.compass.state.pa.us (Pennsylvania's online tool for health and human services)", "Paper: Download form from county assistance office or DHS site, mail or deliver to local county assistance office", "In-person: Local county assistance office (find via PA DHS site)", "Phone: Contact local county assistance office (numbers via PA DHS LIHEAP page or 1-866-550-4355 for general inquiries, but apply via above methods)[1][2][4]"],
    "processing_time": "Allow 30 days for response with written notice of eligibility and benefit amount[1].",
    "waitlist": "Not mentioned; applications accepted December 3, 2025 to May 8, 2026 for regular grants[2].",
    "forms": ["LIHEAP application form (downloadable from county assistance office or COMPASS site)", "COMPASS online application[1][2][4]"],
    "documents": ["Names, birthdates, and Social Security Numbers (or lack thereof) for all household members", "Proof of income for all household members (e.g., pay stubs, tax returns)", "Most recent utility/heating bill", "Proof of residence if needed[3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available to all Pennsylvania residents meeting eligibility; administered via local county assistance offices.",
    "regional_variations": "Benefit amounts vary by county and fuel type via county-specific tables; different local offices handle intake and processing, potentially affecting wait times[1][8].",
    "offices_or_providers": ["Local county assistance offices statewide (locate via https://www.pa.gov or COMPASS)[1][2]"]
  },
  "official_source": "https://www.pa.gov/agencies/dhs/resources/liheap",
  "gotchas": ["No age requirement—open to all qualifying households, not just elderly", "Income limits updated annually (check current year; 2025-2026 figures apply)", "Benefits vary significantly by county, fuel type (e.g., electric, gas, oil), income bracket, and household size—use official benefit table tool", "Application window limited (Dec 3, 2025–May 8, 2026); apply early", "No asset test, but all gross income sources count except specific exclusions", "Crisis grants for emergencies separate from regular heating grants[2][4][5][8]"],
  "data_shape_notes": "Income at 150% FPL with annual updates; no asset test; benefits scale by household size, income range, county, and fuel type via lookup tables; seasonal application window; statewide but county-administered"
}

{
  "name": "SHIP",
  "eligibility": {
    "age": null,
    "income_limits": "No strict income limits; prioritizes people with limited incomes, Medicare beneficiaries under 65 with disabilities, and dually eligible for Medicare/Medicaid. Exact thresholds vary; example for related Medicare Savings Programs: up to ~$1,800/month individual or ~$2,400/month couple[9].",
    "asset_limits": "Not applicable; no asset test mentioned for core SHIP counseling services[7][10].",
    "other_requirements": ["Medicare beneficiary or family/caregiver", "Pennsylvania resident", "Focus on those needing help with Medicare options, appeals, fraud prevention, or cost-saving programs like MSP/Extra Help[7][10]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free one-on-one counseling, education, and assistance on Medicare (Parts A/B/C/D, Medigap), applying for low-income programs (Medicaid, MSP, Extra Help), appeals, rights/procedures, and preventing/detecting/reporting Medicare fraud via Senior Medicare Patrol (SMP). Outreach includes presentations, enrollment events, health fairs[7][10].",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Local SHIP site or 877-839-2675[7]", "Website: shiphelp.org to find/partner with local site[7]", "In-person: Over 2,200 local sites across PA via national network[7]"],
    "processing_time": "Immediate counseling upon contact; no formal processing for services[7][10].",
    "waitlist": null,
    "forms": ["No specific forms; provide Medicare info, income details if applying for cost-saving programs[7]"],
    "documents": ["Medicare card, income proof if seeking MSP/Extra Help eligibility assistance, citizenship/residency if relevant[7][9]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Delivered via local sites/providers (over 2,200 nationally, including PA network); availability, team members (staff/volunteers), and events may vary by county/community[7].",
    "offices_or_providers": ["Local SHIP counselors via shiphelp.org; PA-specific contacts through state Aging or DHS networks (not detailed in results)[7]"]
  },
  "official_source": "https://www.shiphelp.org/ (national); PA details via acl.gov/programs or state aging sites[7]",
  "gotchas": ["Not health insurance or direct financial aid—only free counseling/advocacy; confuses with CHIP (children's insurance)[1][2][7]", "Must contact local site for PA-specific help; national numbers route locally[7]", "Prioritizes limited-income/duals/disabled under 65—others still eligible but not prioritized[7]", "Assists with MSP/Extra Help apps but families must qualify separately[9]"],
  "data_shape_notes": "Counseling/advocacy service via local network, no income/asset test for core help, prioritizes Medicare-related needs for elderly/families; distinct from CHIP (child health insurance)"
}

{
  "name": "SCSEP",
  "eligibility": {
    "age": 55,
    "income_limits": "Household income no more than 125% of the federal poverty level (FPL). Exact dollar amounts vary annually and by household size; families must contact local SCSEP office or check current HHS Poverty Guidelines for 125% FPL table (e.g., for 2025: 1-person ~$19,000; 2-person ~$25,500; scales up per additional member).[1][2][3]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Must live in Pennsylvania (some local providers restrict to specific counties like Philadelphia, Luzerne/Wyoming, or Westmoreland).", "Must be unemployed.", "Authorized to work in the US (Philadelphia-specific).", "Priority: veterans/qualified spouses, over 65, disabled, low literacy/limited English, rural residents, homeless/at-risk, low employment prospects, or prior American Job Center users."[1][3][4][5][6]]
  },
  "benefits": {
    "type": "employment",
    "value": "On-the-job training (average 20 hours/week or 40 hours/every two weeks) at nonprofit/public sites (e.g., schools, hospitals, daycare, senior centers) in roles like childcare, customer service, teacher's aide, computer technician, maintenance, healthcare. Paid highest of federal/state/local minimum wage stipend. Training ~6 months, then bridge to unsubsidized employment; includes resume-building experience, skill training (e.g., computer), job placement assistance.[1][2][3]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Statewide: https://www.pa.gov/services/aging/apply-for-the-senior-community-service-employment-program (apply online).", "Philadelphia: Submit Participant Interest Form at https://www.phila.gov/programs/senior-community-service-employment-program-scsep/; call (215) 686-8450.", "Luzerne/Wyoming: Contact Luzerne County office (no specific form/phone in results).", "Westmoreland: Call 724-925-4084.", "General: Contact local SCSEP grantee/office (state agencies or nonprofits like AARP Foundation); in-person/mail via local providers.[1][3][4][5]"],
    "processing_time": "Not specified statewide; immediate enrollment if eligible and no waitlist.[2]",
    "waitlist": "Common due to high demand and limited slots; varies by region (e.g., possible wait in Luzerne/Wyoming).[2][4]",
    "forms": ["Participant Interest Form (Philadelphia).", "General application via local SCSEP office (no statewide form number specified)."],
    "documents": ["Proof of age, residency, income (to verify ≤125% FPL), unemployment status, work authorization (e.g., SSN). Specifics determined by local office; prepare recent pay stubs, tax returns, ID.[inferred from standard low-income programs; contact local office]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered locally; some providers county-specific (e.g., Philadelphia-only, Luzerne/Wyoming, Westmoreland). Must apply via local grantee.",
    "regional_variations": "Different providers/offices by county/region (e.g., Philadelphia form/phone; Westmoreland phone; Luzerne waitlists). Hours may vary slightly (20/week or 40/biweekly). Contact local for specifics.",
    "offices_or_providers": ["PA Dept of Aging (statewide hub).", "Philadelphia SCSEP: (215) 686-8450.", "Luzerne County.", "Westmoreland: 724-925-4084.", "National grantees like AARP Foundation may operate locally.[1][3][4][5][7]"]
  },
  "official_source": "https://www.pa.gov/services/aging/apply-for-the-senior-community-service-employment-program",
  "gotchas": ["Not direct financial aid—it's paid training employment, not welfare; limited to ~6 months then transition out.", "High demand leads to waitlists; priority groups get first slots.", "Income is family/household-based at 125% FPL—check current guidelines as they update yearly.", "Must be unemployed and seeking work; not for retirees wanting supplemental income without job search.", "Local variations: not all PA counties have same provider/access; verify county-specific rules.[1][2][4][6]"],
  "data_shape_notes": "Administered by multiple local grantees with county restrictions; income at 125% FPL (household size table required annually from HHS); waitlists common; priority tiers for enrollment; no fixed asset test."
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free and available to all regardless of financial status.",
    "asset_limits": "No asset limits; no financial tests apply.",
    "other_requirements": ["Resides (or planning to reside) in a long-term care facility such as nursing homes, assisted living facilities, personal care homes, domiciliary care homes, adult day care centers, or receiving long-term care services in home/community settings.", "Complaint or concern related to quality of care, quality of life, rights, discharge/transfer, service disruption, finances, medications, environment, activities, or similar issues in long-term care.", "Services available to residents, potential residents, families, friends, staff, or community members on behalf of residents."]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Investigation and resolution of complaints; education on rights, procedures, and resources; empowerment through skill-building, resident/family councils, and PEER groups; routine unannounced facility visits; mediation; referrals to long-term care programs; assistance with informed decisions; advocacy for fair treatment, dignity, and quality care. Specific issues addressed: discharge/transfer, service disruption, quality of care/life, residents' finances (e.g., access to funds, Medicare/Medicaid, billing), professional care (medications, nursing, restraints), rights (admission/discharge policies), food/environment/activities.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Contact local Area Agency on Aging (AAA) Ombudsman program (examples: SWPA AAA for Greene/Fayette/Washington Counties via https://www.swpa-aaa.org/community-services/ombudsman-program; Franklin County via https://www.franklincountypa.gov/departments/ombudsman-program/; CARIE at 215-545-5724 or 610-860-5050 for Philadelphia; Center in the Park at 215-844-1829 for NE/NW Philadelphia; Montgomery County via https://www.montgomerycountypa.gov/2832/Ombudsman).", "Statewide assistance: Pennsylvania Department of Aging via https://www.pa.gov/services/aging/request-assistance-from-a-long-term-care-ombudsman or https://www.pa.gov/agencies/aging/aging-programs-and-services/advocacy-education-protection.", "In-person: Local AAA offices or facilities (routine visits by ombudsmen).", "Email: ombudsman@carie.org (Philadelphia example)."],
    "processing_time": "Immediate response to complaints; no formal processing time specified as services are responsive advocacy.",
    "waitlist": null,
    "forms": ["No specific forms required; contact directly to request assistance."],
    "documents": ["No documents needed to initiate; provide details of complaint/concern. Resident permission required before discussing with staff (or via POA if resident unable to consent)."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Services delivered through 52 local Area Agencies on Aging (AAA) covering all Pennsylvania counties.",
    "regional_variations": "Administered locally by AAAs with regional offices/providers (e.g., SWPA AAA for Greene/Fayette/Washington Counties[1]; Franklin County Ombudsman[2]; Lancaster County[3]; PCA for Philadelphia[4]; CARIE for parts of Philadelphia, Center in the Park for other Philadelphia areas[7]; Montgomery County[9]). Trained staff, volunteers, or PEER residents serve specific areas. No differences in core services, but contact points and coverage vary by county.",
    "offices_or_providers": ["Local AAAs; State office: Pennsylvania Department of Aging, 555 Walnut Street, 5th Floor, Harrisburg, PA 17101[10]."]
  },
  "official_source": "https://www.pa.gov/agencies/aging/aging-programs-and-services/advocacy-education-protection",
  "gotchas": ["Not a direct care or financial aid program—provides advocacy only, not healthcare services or funding.", "Must be for long-term care settings (facilities or home-based LTC services); not for independent living without LTC involvement.", "Confidentiality: Ombudsmen require resident permission (or POA) before intervening with staff[3].", "Anyone can contact on behalf of resident (families, friends, staff, public), but priority to resident's wishes.", "Not eligibility for facility admission—helps with complaints/rights once in or seeking LTC.", "Local variation requires finding correct AAA for your county."],
  "data_shape_notes": "no income test; free advocacy services only; county-based delivery via 52 AAAs with no financial eligibility; responsive to complaints rather than pre-qualifying application"
}
